module Concurrency =
  struct
    type nonrec t =
      {
      reservedConcurrentExecutions: ReservedConcurrentExecutions.t option
        [@ocaml.doc
          "The number of concurrent executions that are reserved for this function. For more information, see Managing Lambda reserved concurrency."]}
    type nonrec error =
      [ `InvalidParameterValueException of InvalidParameterValueException.t 
      | `ResourceConflictException of ResourceConflictException.t 
      | `ResourceNotFoundException of ResourceNotFoundException.t 
      | `ServiceException of ServiceException.t 
      | `TooManyRequestsException of TooManyRequestsException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?reservedConcurrentExecutions =
      fun () -> { reservedConcurrentExecutions }
    let error_of_json name json =
      match name with
      | "InvalidParameterValueException" ->
          `InvalidParameterValueException
            (InvalidParameterValueException.of_json json)
      | "ResourceConflictException" ->
          `ResourceConflictException (ResourceConflictException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "ServiceException" ->
          `ServiceException (ServiceException.of_json json)
      | "TooManyRequestsException" ->
          `TooManyRequestsException (TooManyRequestsException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InvalidParameterValueException" ->
          `InvalidParameterValueException
            (InvalidParameterValueException.of_xml xml)
      | "ResourceConflictException" ->
          `ResourceConflictException (ResourceConflictException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "ServiceException" -> `ServiceException (ServiceException.of_xml xml)
      | "TooManyRequestsException" ->
          `TooManyRequestsException (TooManyRequestsException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InvalidParameterValueException e ->
          `Assoc
            [("error", (`String "InvalidParameterValueException"));
            ("details", (InvalidParameterValueException.to_json e))]
      | `ResourceConflictException e ->
          `Assoc
            [("error", (`String "ResourceConflictException"));
            ("details", (ResourceConflictException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `ServiceException e ->
          `Assoc
            [("error", (`String "ServiceException"));
            ("details", (ServiceException.to_json e))]
      | `TooManyRequestsException e ->
          `Assoc
            [("error", (`String "TooManyRequestsException"));
            ("details", (TooManyRequestsException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("ReservedConcurrentExecutions",
           (Option.map x.reservedConcurrentExecutions
              ~f:ReservedConcurrentExecutions.to_value))]
