      let payload = field_map json__ "Payload" Blob.of_json in
      let logResult = field_map json__ "LogResult" String_.of_json in
      let functionError = field_map json__ "FunctionError" String_.of_json in
      let statusCode = field_map json__ "StatusCode" Integer.of_json in
