  end[@@ocaml.doc
       "Invokes a Lambda function. You can invoke a function synchronously (and wait for the response), or asynchronously. By default, Lambda invokes your function synchronously (i.e. theInvocationType is RequestResponse). To invoke a function asynchronously, set InvocationType to Event. Lambda passes the ClientContext object to your function for synchronous invocations only. For synchronous invocations, the maximum payload size is 6 MB. For asynchronous invocations, the maximum payload size is 1 MB. For synchronous invocation, details about the function response, including errors, are included in the response body and headers. For either invocation type, you can find more information in the execution log and trace. When an error occurs, your function may be invoked multiple times. Retry behavior varies by error type, client, event source, and invocation type. For example, if you invoke a function asynchronously and it returns an error, Lambda executes the function up to two more times. For more information, see Error handling and automatic retries in Lambda. For asynchronous invocation, Lambda adds events to a queue before sending them to your function. If your function does not have enough capacity to keep up with the queue, events may be lost. Occasionally, your function may receive the same event multiple times, even if no error occurs. To retain events that were not processed, configure your function with a dead-letter queue. The status code in the API response doesn't reflect function errors. Error codes are reserved for errors that prevent your function from executing, such as permissions errors, quota errors, or issues with your function's code and configuration. For example, Lambda returns TooManyRequestsException if running the function would cause you to exceed a concurrency limit at either the account level (ConcurrentInvocationLimitExceeded) or function level (ReservedFunctionConcurrentInvocationLimitExceeded). For functions with a long timeout, your client might disconnect during synchronous invocation while it waits for a response. Configure your HTTP client, SDK, firewall, proxy, or operating system to allow for long connections with timeout or keep-alive settings. This operation requires permission for the lambda:InvokeFunction action. For details on how to set up permissions for cross-account invocations, see Granting function access to other accounts."]
module InvocationRequest =
  struct
    type nonrec t =
      {
      functionName: NamespacedFunctionName.t
        [@ocaml.doc
          "The name or ARN of the Lambda function, version, or alias. Name formats Function name \226\128\147 my-function (name-only), my-function:v1 (with alias). Function ARN \226\128\147 arn:aws:lambda:us-west-2:123456789012:function:my-function. Partial ARN \226\128\147 123456789012:function:my-function. You can append a version number or alias to any of the formats. The length constraint applies only to the full ARN. If you specify only the function name, it is limited to 64 characters in length."];
      invocationType: InvocationType.t option
        [@ocaml.doc
          "Choose from the following options. RequestResponse (default) \226\128\147 Invoke the function synchronously. Keep the connection open until the function returns a response or times out. The API response includes the function response and additional data. Event \226\128\147 Invoke the function asynchronously. Send events that fail multiple times to the function's dead-letter queue (if one is configured). The API response only includes a status code. DryRun \226\128\147 Validate parameter values and verify that the user or role has permission to invoke the function."];
      logType: LogType.t option
        [@ocaml.doc
          "Set to Tail to include the execution log in the response. Applies to synchronously invoked functions only."];
      clientContext: String_.t option
        [@ocaml.doc
          "Up to 3,583 bytes of base64-encoded data about the invoking client to pass to the function in the context object. Lambda passes the ClientContext object to your function for synchronous invocations only."];
      durableExecutionName: DurableExecutionName.t option
        [@ocaml.doc
          "Optional unique name for the durable execution. When you start your special function, you can give it a unique name to identify this specific execution. It's like giving a nickname to a task."];
      payload: Blob.t option
        [@ocaml.doc
          "The JSON that you want to provide to your Lambda function as input. The maximum payload size is 6 MB for synchronous invocations and 1 MB for asynchronous invocations. You can enter the JSON directly. For example, --payload '\\{ \"key\": \"value\" \\}'. You can also specify a file path. For example, --payload file://payload.json."];
      qualifier: NumericLatestPublishedOrAliasQualifier.t option
        [@ocaml.doc
          "Specify a version or alias to invoke a published version of the function."];
      tenantId: TenantId.t option
        [@ocaml.doc
          "The identifier of the tenant in a multi-tenant Lambda function."]}
    let context_ = "InvocationRequest"
    let make ?invocationType =
      fun ?logType ->
        fun ?clientContext ->
          fun ?durableExecutionName ->
            fun ?payload ->
              fun ?qualifier ->
                fun ?tenantId ->
                  fun ~functionName ->
                    fun () ->
                      {
                        invocationType;
                        logType;
                        clientContext;
                        durableExecutionName;
                        payload;
                        qualifier;
                        tenantId;
                        functionName
                      }
    let of_header_and_body =
      ((fun (xs, pipe) ->
          make
            ~functionName:(NamespacedFunctionName.of_string
                             ((List.Assoc.find_exn
                                 ~equal:String.Caseless.equal) xs
                                "FunctionName"))
            ?invocationType:(Option.map
                               ((List.Assoc.find ~equal:String.Caseless.equal)
                                  xs "X-Amz-Invocation-Type")
                               ~f:InvocationType.of_string)
            ?logType:(Option.map
                        ((List.Assoc.find ~equal:String.Caseless.equal) xs
                           "X-Amz-Log-Type") ~f:LogType.of_string)
            ?clientContext:(Option.map
                              ((List.Assoc.find ~equal:String.Caseless.equal)
